def solve(flight_data, parcel_requests):
    # Validate inputs
    if not isinstance(flight_data, str) or not isinstance(parcel_requests, list):
        raise ValueError("Invalid input types")

    # Parse flight data
    flights = []
    for line in flight_data.strip().splitlines():
        parts = line.split(',')
        if len(parts) < 3:
            continue  # Skip invalid lines
        flight_info = {
            'flight_number': parts[0].strip(),
            'departure_time': parts[1].strip(),
            'available_capacity': int(parts[2].strip())
        }
        flights.append(flight_info)

    # Create reservations
    reservations = []
    for request in parcel_requests:
        parcel_weight = request.get('weight', 0)
        for flight in flights:
            if flight['available_capacity'] >= parcel_weight:
                reservations.append({
                    'flight_number': flight['flight_number'],
                    'parcel_weight': parcel_weight
                })
                flight['available_capacity'] -= parcel_weight
                break  # Move to the next parcel request

    return reservations
